(46, 32, 'Akatsi North District Inter-Circuit Festival of Creative Arts And Culture', 'INTERCIRCU', 'The Akatsi North District 18th Inter-Circuits Festival of Creative Arts and Culture for Basic Schools is a vibrant celebration of creativity, talent, and Ghanaian cultural identity among pupils across the district. Scheduled for 21st November 2025 at Ave Dzalel??, the festival brings together learners, teachers, and community members to showcase the artistic and cultural heritage of Ghana through music, dance, drama, poetry, and visual arts.\r\nUnder the theme ???Cultural Education: Nurturing and Preserving Ghanaian Values,??? the event aims to promote cultural literacy and inspire pride in indigenous traditions among young people. It also serves as a platform for schools to exchange ideas, foster unity, and demonstrate the educational importance of arts and culture in national development.\r\nParticipants and guests will enjoy traditional performances, creative art exhibitions, and cultural showcases that reflect the beauty and diversity of Ghana???s heritage. The festival promises an atmosphere of learning, entertainment, and community bonding, reaffirming the commitment of the Akatsi North District Education Directorate to holistic education and cultural preservation.', 'public/uploads/events/events_68f51cdeded84.jpg', '2025-10-20 15:21:00', '2025-11-21 15:21:00', 1.00, 1, 'active', 'public', 'pending', NULL, 27, NULL, NULL, NULL, NULL, NULL, '2025-10-19 19:22:31', '2025-10-20 16:46:40', 1, NULL, NULL),
(47, 34, 'Breman Odwira Beauty Pageant', 'BREMANODWI', '', NULL, '2025-10-27 00:00:00', '2025-11-07 03:30:00', 1.00, 1, 'active', 'public', 'pending', NULL, 29, NULL, NULL, NULL, NULL, NULL, '2025-10-28 13:09:20', '2025-11-07 08:31:31', 0, NULL, NULL),
(48, 31, 'Assin South Sports Excellence and Legacy Awards', 'ASSELA', 'Assin South Schools and Community Sports Excellence and Legacy awards. Celebrating Sports personalities in the Assin South District for the 2024/2025 academic year.', NULL, '2025-11-17 05:00:00', '2026-03-07 21:00:00', 2.00, 1, 'draft', 'public', 'pending', NULL, 26, NULL, NULL, NULL, NULL, NULL, '2025-11-01 20:29:32', '2025-11-01 20:29:32', 1, NULL, NULL);
